public class BinaryTreeDemo {
    // Storage: Node structure representation
    public static class Node {
        public int val;
        public Node left;
        public Node right;

        public Node(int val) {
            this.val = val;
            left = null;
            right = null;
        }
    }

    public static Node createSampleTree() {
        // Storage: Allocating nodes
        Node root = new Node(1);
        root.left = new Node(2);
        root.right = new Node(3);
        root.left.left = new Node(4);

        // Output: Return created tree
        return root;
    }
}

public class TreeTraversals {
    // Storage: Tree Node Representation
    public static class TreeNode {
        public int val;
        public TreeNode left, right;
        public TreeNode(int val) { this.val = val; }
    }

    // Process & Output: Recursive Inorder Traversal
    public static void inorder(TreeNode root) {
        if (root == null) return;

        inorder(root.left);                  // Left
        System.out.print(root.val + " ");   // Root (Output)
        inorder(root.right);                 // Right
    } 
}

