import java.util.LinkedList;
import java.util.Queue;

public class LevelOrderInsertion {
    public static void insert(TreeTraversals.TreeNode root, int key) {
        // Input: root node and key value
        if (root == null) return;

        // Storage: Queue for level order traversal
        Queue<TreeTraversals.TreeNode> queue = new LinkedList<>();
        queue.add(root);

        // Process: Traverse levels
        while (!queue.isEmpty()) {
            TreeTraversals.TreeNode temp = queue.peek(); // Storage
            queue.remove();

            if (temp.left == null) {
                temp.left = new TreeTraversals.TreeNode(key); // Storage: new node
                break;
            } else {
                queue.add(temp.left);
            }

            if (temp.right == null) {
                temp.right = new TreeTraversals.TreeNode(key); // Storage: new node
                break;
            } else {
                queue.add(temp.right);
            }
        }
    }
}

