public class BinaryTreeHeight {
    public static int maxDepth(TreeTraversals.TreeNode node) {
        // Input: node reference

        // Process: Base case
        if (node == null) {
            return 0; // Output
        }

        // Process: Recurse left and right heights
        int leftDepth = maxDepth(node.left);   // Storage
        int rightDepth = maxDepth(node.right); // Storage

        // Output: return maximum depth + 1 for root
        return Math.max(leftDepth, rightDepth) + 1;
    }
}

import java.util.LinkedList;
import java.util.Queue;

public class BinaryTreeDeletion {
    public static TreeTraversals.TreeNode deleteNode(TreeTraversals.TreeNode root, int key) {
        // Input: root node and key to delete
        if (root == null) return null;
        if (root.left == null && root.right == null) {
            if (root.val == key) return null;
            return root;
        }

        // Storage: Queue for BFS
        Queue<TreeTraversals.TreeNode> q = new LinkedList<>();
        q.add(root);

        TreeTraversals.TreeNode temp = null;     // Storage
        TreeTraversals.TreeNode keyNode = null;  // Storage

        // Process: BFS to find target node and deepest node
        while (!q.isEmpty()) {
            temp = q.peek();
            q.remove();

            if (temp.val == key) keyNode = temp;
            if (temp.left != null) q.add(temp.left);
            if (temp.right != null) q.add(temp.right);
        }

        if (keyNode != null) {
            int x = temp.val; // Storage: deepest value
            deleteDeepest(root, temp);
            keyNode.val = x; // Process: replace data
        }
        return root; // Output
    }

    private static void deleteDeepest(TreeTraversals.TreeNode root, TreeTraversals.TreeNode dNode) {
        Queue<TreeTraversals.TreeNode> q = new LinkedList<>();
        q.add(root);
        while (!q.isEmpty()) {
            TreeTraversals.TreeNode temp = q.poll();
            if (temp == dNode) { temp = null; return; }
            if (temp.right != null) {
                if (temp.right == dNode) { temp.right = null; return; }
                else q.add(temp.right);
            }
            if (temp.left != null) {
                if (temp.left == dNode) { temp.left = null; return; }
                else q.add(temp.left);
            }
        }
    }
}
